class LoggingInterceptor : HttpLoggingInterceptor.Logger {
    override fun log(message: String) {
        Timber.tag("HTTP_LOG").d(message)
    }
}

class DetailedLoggingTree : Timber.DebugTree() {
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        if (t != null) {
            Timber.tag(tag ?: "LOG").log(priority, message, t)
        } else {
            Timber.tag(tag ?: "LOG").log(priority, message)
        }
    }
    
    override fun createStackElementTag(element: StackTraceElement): String {
        return super.createStackElementTag(element) + ":" + element.lineNumber
    }
}

